function lint(body:string,schemaJson:any){const out:any[]={errors:[]} as any;let doc;try{doc=YAML.parseAllDocuments(body);}catch(e:any){return [{line:0,col:0,msg:'YAML parse: '+e.message}];}const errors:any[]=[];for(let i=0;i<doc.length;i++){const d=doc[i];const validator=ajv.compile(schemaJson);if(!validator(d.toJSON())){for(const err of validator.errors||[])errors.push({docIdx:i,path:err.instancePath,msg:err.message});}}return errors;}
export function registerCfgNamespace(nsp:any){
  nsp.use(authMw);
  nsp.on('connection',(socket:any)=>{
    const uid=String(socket.data.user.id);
    socket.on('cfg:open',async({cfgId}:any,ack:any)=>{await socket.join(`cfg:${cfgId}`);const r=await pool.query('SELECT c.*,s.schema_json FROM configs c LEFT JOIN config_schemas s ON s.id=c.schema_id WHERE c.id=$1',[cfgId]);ack({config:r.rows[0]});});
    socket.on('lint',async({cfgId,body}:any,ack:any)=>{const s=await pool.query('SELECT s.schema_json FROM configs c JOIN config_schemas s ON s.id=c.schema_id WHERE c.id=$1',[cfgId]);const diag=lint(body,s.rows[0]?.schema_json||{});io.of('/cfg').to(`cfg:${cfgId}`).emit('diagnostics',{diag});ack({diag});});
    socket.on('save',async({cfgId,body,expectedVersion}:any,ack:any)=>{const r=await pool.query('UPDATE configs SET body=$1,version=version+1 WHERE id=$2 AND version=$3 RETURNING version',[body,cfgId,expectedVersion]);if(r.rowCount===0)return ack({error:'conflict'});ack({version:r.rows[0].version});});
  });
