export async function reportProbe(serviceId:string,region:string,ok:boolean,latencyMs:number){
  await Probe.create({serviceId,region,ok,latencyMs,ts:new Date()});
  const recent=await Probe.find({serviceId,ts:{$gt:new Date(Date.now()-60_000)}}).lean();
  const byRegion=new Map<string,boolean>();
  for(const p of recent){if(!byRegion.has(p.region))byRegion.set(p.region,p.ok);}
