export async function preview(subId:number,toPlanId:number){
  const s=await pool.query('SELECT renews_at,price_cents,starts_at FROM subscriptions WHERE id=$1',[subId]);
  const newPlan=await pool.query('SELECT price_cents FROM plans WHERE id=$1',[toPlanId]);
