export async function popCall(agentId:number){
  const client=await pool.connect();
  try{await client.query('BEGIN');
    const skills=(await client.query('SELECT skills FROM agents WHERE id=$1',[agentId])).rows[0].skills;
    const r=await client.query(`SELECT id,phone FROM call_queue WHERE status='waiting' AND skill=ANY($1::text[]) ORDER BY queued_at ASC LIMIT 1 FOR UPDATE SKIP LOCKED`,[skills]);
    if(r.rowCount===0){await client.query('ROLLBACK');return null;}
    await client.query(`UPDATE call_queue SET status='active',assigned_agent=$1 WHERE id=$2`,[agentId,r.rows[0].id]);
    await client.query('COMMIT');
    io.of('/cc').to(`agent:${agentId}`).emit('call:popped',{callId:String(r.rows[0].id),phone:r.rows[0].phone});
    return r.rows[0];
  }catch(e){await client.query('ROLLBACK');throw e;}finally{client.release();}
}
